    #[test]
    fn anthropic_rediscovery_replaces_stale_static_models() {
        let mut config = ProvidersConfig::default();
        config
            .providers
            .insert("anthropic".into(), moltis_config::schema::ProviderEntry {
                enabled: true,
                api_key: Some(secret("sk-ant-test")),
                fetch_models: true,
                ..Default::default()
            });

