1026→/// Check if a model supports vision (image inputs).
1027→///
1028→/// Vision-capable models can process images in tool results and user messages.
1029→/// When true, the runner sends images as multimodal content blocks rather than
1030→/// stripping them from the context.
1031→///
1032→/// Uses a deny-list approach: most modern LLMs support vision, so unknown
1033→/// models default to `true`. The consequence of a false positive (sending
1034→/// images to a text-only model) is an API error — visible and diagnosable.
1035→/// The consequence of a false negative (stripping images from a capable model)
1036→/// is a silent failure that confuses users.
1037→pub fn supports_vision_for_model(model_id: &str) -> bool {
1038→    let id = capability_model_id(model_id);
1039→
1040→    // ── Known text-only models ──────────────────────────────────────
1041→    // Code-focused models
1042→    if id.starts_with("codestral") {
1043→        return false;
1044→    }
1045→    // Legacy OpenAI models without vision
1046→    if id.starts_with("gpt-3.5") || id.starts_with("text-") || id.starts_with("gpt-4-") {
1047→        // gpt-4-turbo and gpt-4-vision variants support vision
1048→        if id.starts_with("gpt-4-turbo") || id.starts_with("gpt-4-vision") {
1049→            return true;
1050→        }
1051→        return false;
1052→    }
1053→    // Z.AI GLM text-only models (vision variants contain 'v' suffix)
1054→    if id.starts_with("glm-") && !id.contains('v') {
1055→        return false;
1056→    }
1057→
1058→    // ── Default: assume vision support ──────────────────────────────
1059→    true
1060→}
