 79→fn title_case_chunk(chunk: &str) -> String {
 80→    if chunk.is_empty() {
 81→        return String::new();
 82→    }
 83→    let mut chars = chunk.chars();
 84→    match chars.next() {
 85→        Some(first) => {
 86→            let mut out = String::new();
 87→            out.push(first.to_ascii_uppercase());
 88→            out.push_str(chars.as_str());
