246→    api_key: secrecy::Secret<String>,
247→    base_url: String,
248→) -> anyhow::Result<Vec<crate::DiscoveredModel>> {
249→    let client = crate::shared_http_client();
250→    let mut models = Vec::new();
251→    let mut seen_ids = HashSet::new();
252→    let mut seen_after_ids = HashSet::new();
253→    let mut after_id: Option<String> = None;
254→
255→    loop {
256→        let mut request = client
257→            .get(models_endpoint(&base_url))
258→            .timeout(Duration::from_secs(15))
259→            .header("x-api-key", api_key.expose_secret())
260→            .header("anthropic-version", "2023-06-01")
261→            .header("accept", "application/json");
262→
263→        if let Some(ref after) = after_id {
264→            request = request.query(&[("after_id", after)]);
265→        }
266→
267→        let response = request.send().await?;
268→        let status = response.status();
269→        let body = response.text().await?;
270→        if !status.is_success() {
271→            anyhow::bail!("anthropic models API error HTTP {status}: {body}");
272→        }
273→
274→        let payload: serde_json::Value = serde_json::from_str(&body)?;
275→        for model in parse_models_payload(&payload) {
276→            if seen_ids.insert(model.id.clone()) {
277→                models.push(model);
278→            }
279→        }
280→
281→        let has_more = payload
282→            .get("has_more")
283→            .and_then(serde_json::Value::as_bool)
284→            .unwrap_or(false);
285→        let next_after_id = payload
286→            .get("last_id")
287→            .and_then(serde_json::Value::as_str)
288→            .map(str::trim)
289→            .filter(|id| !id.is_empty())
290→            .map(ToOwned::to_owned);
291→
292→        if !has_more {
293→            break;
294→        }
295→
296→        let Some(next_after_id) = next_after_id else {
297→            break;
