1543→    fn register_dynamic_source_models(
1544→        &mut self,
1545→        source: &dyn DynamicModelDiscovery,
1546→        config: &ProvidersConfig,
1547→        catalog: Vec<DiscoveredModel>,
1548→    ) {
1549→        let Some(models) = Self::desired_models_for_dynamic_source(source, config, catalog) else {
1550→            return;
1551→        };
1552→
1553→        for model in models {
1554→            if self.has_provider_model(source.provider_name(), &model.id) {
1555→                continue;
1556→            }
1557→            let provider = source.build_provider(model.id.clone(), config);
1558→            self.register(
1559→                ModelInfo {
1560→                    id: model.id.clone(),
1561→                    provider: source.provider_name().to_string(),
1562→                    display_name: source.display_name(&model.id, &model.display_name),
1563→                    created_at: model.created_at,
1564→                    recommended: model.recommended,
1565→                },
1566→                provider,
1567→            );
1568→        }
1569→    }
1570→
1571→    #[cfg(any(feature = "provider-openai-codex", feature = "provider-github-copilot"))]
1572→    fn refresh_dynamic_source_models(
1573→        &mut self,
1574→        source: &dyn DynamicModelDiscovery,
1575→        config: &ProvidersConfig,
1576→    ) -> bool {
1577→        if !source.is_enabled_and_authenticated(config) {
1578→            return false;
1579→        }
1580→        if !source.should_fetch_models(config) {
1581→            return false;
1582→        }
1583→
1584→        let live_catalog = match source.live_models() {
1585→            Ok(models) => models,
1586→            Err(err) => {
1587→                tracing::warn!(
1588→                    provider = source.provider_name(),
1589→                    error = %err,
1590→                    "skipping dynamic model refresh because live fetch failed"
1591→                );
1592→                return false;
1593→            },
1594→        };
1595→
1596→        let Some(next_models) =
1597→            Self::desired_models_for_dynamic_source(source, config, live_catalog)
1598→        else {
1599→            return false;
1600→        };
1601→
1602→        let new_entries: Vec<(ModelInfo, Arc<dyn LlmProvider>)> = next_models
1603→            .into_iter()
1604→            .map(|model| {
1605→                (
1606→                    ModelInfo {
1607→                        id: model.id.clone(),
1608→                        provider: source.provider_name().to_string(),
1609→                        display_name: source.display_name(&model.id, &model.display_name),
1610→                        created_at: model.created_at,
1611→                        recommended: model.recommended,
1612→                    },
1613→                    source.build_provider(model.id, config),
1614→                )
1615→            })
1616→            .collect();
1617→
1618→        // Replace stale provider entries atomically only after successful fetch.
1619→        let stale_ids: Vec<String> = self
1620→            .models
1621→            .iter()
1622→            .filter(|m| m.provider == source.provider_name())
1623→            .map(|m| m.id.clone())
1624→            .collect();
1625→        for model_id in &stale_ids {
1626→            self.providers.remove(model_id);
1627→        }
1628→        self.models.retain(|m| m.provider != source.provider_name());
1629→        for (info, provider) in new_entries {
1630→            self.register(info, provider);
1631→        }
1632→
1633→        true
1634→    }
