                self.commands
                    .lock()
                    .expect("mock exec commands mutex poisoned")
                    .push(command.to_string());
            }
            Ok(serde_json::json!({
                "stdout": "ok\n",
                "stderr": "",
                "exit_code": 0
            }))
        }
    }

