        let completions = Arc::new(AtomicUsize::new(0));
        let stream_outbound: Arc<dyn moltis_channels::plugin::ChannelStreamOutbound> =
            Arc::new(MockChannelStreamOutbound {
                deltas: Arc::clone(&deltas),
