        assert!(completed.contains(&ChannelReplyTargetKey::from(&target)));
        assert_eq!(completions.load(Ordering::SeqCst), 1);
        assert_eq!(deltas.lock().await.join(""), "Hello");
        assert_eq!(reply_tos.lock().await.as_slice(), &[Some("55".to_string())]);
    }

