        let now = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap_or_default()
            .as_secs() as i64;
        let recent_gpt = now - 10 * 24 * 60 * 60; // 10 days ago
        let recent_babbage = now - 30 * 24 * 60 * 60; // 30 days ago

        let mut registry = ProviderRegistry::empty();
        registry.register(
